#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    int is_leaf;
    int num_keys;
} knode;

__kernel void findK(
    const long maxheight,
    __global knode* knodes,
    const long knodes_elem,
    __global record* records,
    __global long* currKnode,
    __global long* offset,
    __global int* keys,
    __global record* ans)
{
    int global_id = get_global_id(0);
    int local_id = get_local_id(0);
    int group_size = get_local_size(0);
    int bid = global_id / group_size;

    if (bid >= get_global_size(0) / group_size) return;

    // Initialize ans[bid].value to -1 once per bid by one thread
    if (local_id == 0) {
        ans[bid].value = -1;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (long i = 0; i < maxheight; i++) {
        int thid = local_id;
        if (thid < group_size) {
            int curr_node_idx = (int)currKnode[bid];
            if (curr_node_idx >= knodes_elem) continue;
            knode curr_node = knodes[curr_node_idx];
            if (keys[bid] >= curr_node.keys[thid] && keys[bid] < curr_node.keys[thid + 1]) {
                int idx = curr_node.indices[thid];
                if (idx < knodes_elem) {
                    offset[bid] = idx;
                }
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        if (local_id == 0) {
            currKnode[bid] = offset[bid];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    int curr_node_idx = (int)currKnode[bid];
    if (curr_node_idx < knodes_elem) {
        knode curr_node = knodes[curr_node_idx];
        int thid = local_id;
        if (thid < group_size) {
            if (keys[bid] == curr_node.keys[thid]) {
                int rec_idx = curr_node.indices[thid];
                ans[bid].value = records[rec_idx].value;
            }
        }
    }
}

