    int num_keys;
} knode;

__kernel void findK2(
    const long maxheight,
    __global knode* knodes,
    const long knodes_elem,
    const int order,
    const int count,
    __global long* currKnode,
    __global long* offset,
    __global long* lastKnode,
    __global long* offset_2,
    __global int* start,
    __global int* end,
    __global int* recstart,
    __global int* reclength)
{
    int global_id = get_global_id(0);
    int local_id = get_local_id(0);
    int group_size = get_local_size(0);
    int bid = global_id / group_size;

    if (bid >= count) return;

    // Initialize recstart and reclength once per bid by one thread
    if (local_id == 0) {
        recstart[bid] = 0;
        reclength[bid] = 0;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (long i = 0; i < maxheight; i++) {
        int thid = local_id;
        if (thid < group_size) {
            int curr_node_idx = (int)currKnode[bid];
            int last_node_idx = (int)lastKnode[bid];
            if (curr_node_idx < knodes_elem) {
                knode curr_node = knodes[curr_node_idx];
                if (start[bid] >= curr_node.keys[thid] && start[bid] < curr_node.keys[thid + 1]) {
                    int idx = curr_node.indices[thid];
                    if (idx < knodes_elem) {
                        offset[bid] = idx;
                    }
                }
            }
            if (last_node_idx < knodes_elem) {
                knode last_node = knodes[last_node_idx];
                if (end[bid] >= last_node.keys[thid] && end[bid] < last_node.keys[thid + 1]) {
                    int idx = last_node.indices[thid];
                    if (idx < knodes_elem) {
                        offset_2[bid] = idx;
                    }
                }
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        if (local_id == 0) {
            currKnode[bid] = offset[bid];
            lastKnode[bid] = offset_2[bid];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    int curr_node_idx = (int)currKnode[bid];
    int last_node_idx = (int)lastKnode[bid];
    int thid = local_id;

    if (curr_node_idx < knodes_elem && thid < group_size) {
        knode curr_node = knodes[curr_node_idx];
        if (start[bid] == curr_node.keys[thid]) {
            recstart[bid] = curr_node.indices[thid];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (last_node_idx < knodes_elem && thid < group_size) {
        knode last_node = knodes[last_node_idx];
        if (end[bid] == last_node.keys[thid]) {
            reclength[bid] = last_node.indices[thid] - recstart[bid] + 1;
        }
    }
}
